# Explorer packet solve S41-T1-A-E2: three-route assess for contract gate
def assess(record: dict) -> str:
    required = {'status', 'method', 'created', 'resource', 'case_id'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if (not (record["status"] == 200 and record["method"] == "GET")) else 'RETURN_CORRECT_HTTP_STATUS'

valid = {'case_id': 'CASO-ARE-041-1A', 'method': 'POST', 'resource': '/v1/jobs', 'created': True, 'status': 201}
invalid = {'case_id': 'CASO-ARE-041-1A', 'method': 'POST', 'resource': '/v1/jobs', 'created': True, 'status': 201}
incomplete = {**valid}
incomplete.pop('status', None)
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

